vec3 oc_paintedSurface(vec2 uv, vec3 color, float time) {
 float n1 = fract(sin(dot(floor(uv * 220.0), vec2(12.9898,78.233))) * 43758.5453);
 float n2 = fract(sin(dot(floor((uv + vec2(0.013, -0.021)) * 90.0), vec2(39.3468,11.135))) * 24634.6345);
 float grain = (n1 - 0.5) * 0.08 + (n2 - 0.5) * 0.05;
 float edgeFade = smoothstep(0.0, 0.18, uv.x) * smoothstep(0.0, 0.18, 1.0 - uv.x) * smoothstep(0.0, 0.16, uv.y) * smoothstep(0.0, 0.16, 1.0 - uv.y);
 color *= mix(0.92, 1.0, edgeFade);
 color.r += 0.03;
 color.g += 0.015;
 color += grain;
 return color;
}

float oc_discMask(vec2 p, float r, float w, float breakArc) {
 float a = atan(p.y, p.x);
 float d = abs(length(p) - r);
 float gap = smoothstep(breakArc, breakArc + 0.08, abs(a));
 return (1.0 - smoothstep(w, w + 0.01, d)) * gap;
}
